// --- ASSET MANAGER ---
class AssetManager {
  constructor() {
    this.images = {};
    this.loadingCount = 0;
    this.loadedCount = 0;
    this.onProgress = null;
    this.onComplete = null;
  }

  loadImage(key, url) {
    return new Promise((resolve, reject) => {
      const img = new Image();
      img.onload = () => {
        this.images[key] = img;
        this.loadedCount++;
        if (this.onProgress) this.onProgress(this.loadedCount, this.loadingCount);
        resolve(img);
      };
      img.onerror = () => {
        // Create placeholder on error
        this.images[key] = this.createPlaceholder(key);
        this.loadedCount++;
        if (this.onProgress) this.onProgress(this.loadedCount, this.loadingCount);
        resolve(this.images[key]);
      };
      this.loadingCount++;
      img.src = url;
    });
  }

  createPlaceholder(key) {
    const canvas = document.createElement('canvas');
    canvas.width = 64;
    canvas.height = 64;
    const ctx = canvas.getContext('2d');
    ctx.fillStyle = '#888';
    ctx.fillRect(0, 0, 64, 64);
    ctx.fillStyle = '#555';
    ctx.font = '10px monospace';
    ctx.textAlign = 'center';
    ctx.fillText(key.substring(0, 10), 32, 34);
    return canvas;
  }

  get(key) {
    return this.images[key];
  }

  async loadAll(sprites) {
    const promises = [];
    for (const [key, url] of Object.entries(sprites)) {
      promises.push(this.loadImage(key, url));
    }
    await Promise.all(promises);
    if (this.onComplete) this.onComplete();
  }
}

// --- MAP ENGINE ---
class MapEngine {
  constructor(ctx, assets) {
    this.ctx = ctx;
    this.assets = assets;
    this.map = this.generateMap();
    this.player = { x: 5, y: 5, facing: 'down' };
    this.npc = { x: 12, y: 8, facing: 'left', talked: false };
    this.dialogActive = false;
    this.dialogText = '';
    this.dialogCharIndex = 0;
    this.dialogQueue = [];
    this.inputLocked = false;
    this.dialogComplete = false;
  }

  generateMap() {
    const map = [];
    for (let y = 0; y < MAP_ROWS; y++) {
      map[y] = [];
      for (let x = 0; x < MAP_COLS; x++) {
        if (y === 0 || y === MAP_ROWS - 1 || x === 0 || x === MAP_COLS - 1) {
          map[y][x] = TILES.ROAD_H; // Border road
        } else if (y === 3 && x > 2 && x < MAP_COLS - 2) {
          map[y][x] = TILES.ROAD_H; // Top path
        } else if (y === 10 && x > 2 && x < MAP_COLS - 2) {
          map[y][x] = TILES.ROAD_H; // Middle path
        } else if (x === 3 && y > 2 && y < MAP_ROWS - 2) {
          map[y][x] = TILES.ROAD_V; // Left path
        } else if (x === 15 && y > 2 && y < MAP_ROWS - 2) {
          map[y][x] = TILES.ROAD_V; // Right path
        } else if (Math.random() < 0.15) {
          map[y][x] = TILES.TALL_GRASS; // Tall grass patches
        } else {
          map[y][x] = TILES.GRASS;
        }
      }
    }
    // Mark NPC position as road
    map[this.npc.y][this.npc.x] = TILES.ROAD_H;
    return map;
  }

  drawTile(x, y, tileType) {
    const px = x * TILE_SIZE;
    const py = y * TILE_SIZE;
    switch (tileType) {
      case TILES.GRASS:
        this.ctx.fillStyle = '#3a5f0b';
        this.ctx.fillRect(px, py, TILE_SIZE, TILE_SIZE);
        this.ctx.fillStyle = '#4a7f1b';
        for (let i = 0; i < 3; i++) {
          this.ctx.fillRect(px + 3 + i * 4, py + 2, 2, 4);
          this.ctx.fillRect(px + 2 + i * 5, py + 8, 2, 4);
        }
        break;
      case TILES.TALL_GRASS:
        this.ctx.fillStyle = '#2d4a0f';
        this.ctx.fillRect(px, py, TILE_SIZE, TILE_SIZE);
        this.ctx.fillStyle = '#5a8f2b';
        for (let i = 0; i < 4; i++) {
          this.ctx.fillRect(px + 2 + i * 4, py + 1, 2, 6);
          this.ctx.fillRect(px + 3 + i * 4, py + 8, 2, 7);
        }
        break;
      case TILES.ROAD_H:
        this.ctx.fillStyle = '#8b7355';
        this.ctx.fillRect(px, py, TILE_SIZE, TILE_SIZE);
        this.ctx.fillStyle = '#9b8365';
        for (let i = 0; i < 4; i++) {
          this.ctx.fillRect(px + i * 4, py + 6, 3, 2);
        }
        break;
      case TILES.ROAD_V:
        this.ctx.fillStyle = '#8b7355';
        this.ctx.fillRect(px, py, TILE_SIZE, TILE_SIZE);
        this.ctx.fillStyle = '#9b8365';
        for (let i = 0; i < 4; i++) {
          this.ctx.fillRect(px + 6, py + i * 4, 2, 3);
        }
        break;
      default:
        this.ctx.fillStyle = '#8b7355';
        this.ctx.fillRect(px, py, TILE_SIZE, TILE_SIZE);
    }
  }

  drawPlayer() {
    const px = this.player.x * TILE_SIZE;
    const py = this.player.y * TILE_SIZE;
    const sprite = this.assets.get('player');
    if (sprite) {
      this.ctx.drawImage(sprite, px - 8, py - 16, 32, 32);
    } else {
      // Fallback player sprite
      this.ctx.fillStyle = '#ff6b6b';
      this.ctx.fillRect(px, py, 16, 16);
      this.ctx.fillStyle = '#ffaaaa';
      this.ctx.fillRect(px + 4, py + 2, 8, 6);
    }
  }

  drawNPC() {
    const px = this.npc.x * TILE_SIZE;
    const py = this.npc.y * TILE_SIZE;
    const sprite = this.assets.get('rival');
    if (sprite) {
      this.ctx.drawImage(sprite, px - 8, py - 16, 32, 32);
    } else {
      this.ctx.fillStyle = '#6b6bff';
      this.ctx.fillRect(px, py, 16, 16);
      this.ctx.fillStyle = '#aaaaff';
      this.ctx.fillRect(px + 4, py + 2, 8, 6);
    }
  }

  draw() {
    // Draw map
    for (let y = 0; y < MAP_ROWS; y++) {
      for (let x = 0; x < MAP_COLS; x++) {
        this.drawTile(x, y, this.map[y][x]);
      }
    }
    // Draw NPC first (lower y)
    this.drawNPC();
    // Draw player
    this.drawPlayer();
    // Draw dialog if active
    if (this.dialogActive) {
      this.drawDialog();
    }
  }

  drawDialog() {
    const boxX = 20;
    const boxY = 220;
    const boxW = 440;
    const boxH = 80;
    // Dialog box background
    this.ctx.fillStyle = '#f8f8f8';
    this.ctx.fillRect(boxX, boxY, boxW, boxH);
    this.ctx.strokeStyle = '#5c4a3a';
    this.ctx.lineWidth = 3;
    this.ctx.strokeRect(boxX, boxY, boxW, boxH);
    // Inner border
    this.ctx.strokeStyle = '#d8c8b8';
    this.ctx.lineWidth = 1;
    this.ctx.strokeRect(boxX + 4, boxY + 4, boxW - 8, boxH - 8);
    // Dialog text
    this.ctx.fillStyle = '#3a3a3a';
    this.ctx.font = '14px "Courier New"';
    const displayText = this.dialogText.substring(0, this.dialogCharIndex);
    const lines = this.wrapText(displayText, boxW - 30);
    lines.slice(0, 3).forEach((line, i) => {
      this.ctx.fillText(line, boxX + 15, boxY + 25 + i * 18);
    });
    // Continue indicator
    if (this.dialogComplete && this.dialogCharIndex >= this.dialogText.length) {
      this.ctx.fillStyle = '#5c4a3a';
      this.ctx.fillText('▼', boxX + boxW - 25, boxY + boxH - 15);
    }
  }

  wrapText(text, maxWidth) {
    const words = text.split(' ');
    const lines = [];
    let currentLine = '';
    for (const word of words) {
      const testLine = currentLine ? currentLine + ' ' + word : word;
      if (this.ctx.measureText(testLine).width > maxWidth) {
        lines.push(currentLine);
        currentLine = word;
      } else {
        currentLine = testLine;
      }
    }
    if (currentLine) lines.push(currentLine);
    return lines;
  }

  updateDialog() {
    if (!this.dialogActive) return false;
    if (this.dialogCharIndex < this.dialogText.length) {
      this.dialogCharIndex += 0.5;
      if (this.dialogCharIndex > this.dialogText.length) {
        this.dialogCharIndex = this.dialogText.length;
      }
    } else {
      this.dialogComplete = true;
    }
    return true;
  }

  canMove(dx, dy) {
    const newX = this.player.x + dx;
    const newY = this.player.y + dy;
    if (newX < 0 || newX >= MAP_COLS || newY < 0 || newY >= MAP_ROWS) return false;
    if (newX === this.npc.x && newY === this.npc.y) return false;
    return true;
  }

  movePlayer(dx, dy) {
    if (this.inputLocked || this.dialogActive) return;
    if (!this.canMove(dx, dy)) return;
    this.player.x += dx;
    this.player.y += dy;
    if (dx > 0) this.player.facing = 'right';
    else if (dx < 0) this.player.facing = 'left';
    else if (dy > 0) this.player.facing = 'down';
    else if (dy < 0) this.player.facing = 'up';
  }

  interact() {
    if (this.inputLocked) return;
    if (this.dialogActive) {
      if (this.dialogComplete && this.dialogCharIndex >= this.dialogText.length) {
        this.dialogActive = false;
        this.dialogQueue.shift();
        if (this.dialogQueue.length > 0) {
          this.startNextDialog();
        } else {
          // Trigger battle after dialog
          this.npc.talked = true;
          return 'BATTLE';
        }
      } else {
        this.dialogCharIndex = this.dialogText.length;
        this.dialogComplete = true;
      }
      return null;
    }
    // Check if near NPC
    const dx = Math.abs(this.player.x - this.npc.x);
    const dy = Math.abs(this.player.y - this.npc.y);
    if ((dx <= 1 && dy <= 1) && !(dx === 0 && dy === 0)) {
      if (!this.npc.talked) {
        this.dialogQueue = [
          "Hey there! You look like you could use some battle practice.",
          "Let's see what you've got, shall we?",
          "Come on, let's battle!"
        ];
        this.startNextDialog();
      } else {
        this.dialogQueue = ["You ready for another round?"];
        this.startNextDialog();
      }
    }
    return null;
  }

  startNextDialog() {
    this.dialogText = this.dialogQueue[0];
    this.dialogCharIndex = 0;
    this.dialogComplete = false;
    this.dialogActive = true;
  }

  isNearNPC() {
    const dx = Math.abs(this.player.x - this.npc.x);
    const dy = Math.abs(this.player.y - this.npc.y);
    return (dx <= 1 && dy <= 1);
  }
}

// --- BATTLE ENGINE ---
class BattleEngine {
  constructor(ctx, assets) {
    this.ctx = ctx;
    this.assets = assets;
    this.active = false;
    this.phase = 'intro'; // intro, player_turn, enemy_turn, animate, result
    this.inputLocked = true;
    this.message = '';
    this.messageQueue = [];
    this.charIndex = 0;
    this.messageComplete = false;
    this.selectedMove = null;
    this.actionSelection = 0; // 0: Fight, 1: Bag, 2: Run
    this.hpBarAnimating = false;
    this.playerHP = 0;
    this.enemyHP = 0;
    this.playerHPMax = 0;
    this.enemyHPMax = 0;
    this.damageAnimTimer = 0;
    this.effectivenessText = '';
    this.shakeX = 0;
    this.shakeTimer = 0;
    this.flashTimer = 0;
    this.transitionPhase = 0;
    this.transitionTimer = 0;
    this.transitionActive = false;
    this.onBattleEnd = null;
  }

  initBattle(playerData, enemyData) {
    this.player = this.createPokemon(playerData, 5);
    this.enemy = this.createPokemon(enemyData, 5);
    this.playerHP = this.player.currentHP;
    this.enemyHP = this.enemy.currentHP;
    this.playerHPMax = this.player.currentHP;
    this.enemyHPMax = this.enemy.currentHP;
    this.active = true;
    this.phase = 'intro';
    this.inputLocked = true;
    this.messageQueue = [`A wild ${this.enemy.name} appeared!`];
    this.charIndex = 0;
    this.message = '';
    this.messageComplete = false;
    this.transitionActive = true;
    this.transitionPhase = 0;
    this.transitionTimer = 0;
    this.actionSelection = 0;
  }

  createPokemon(data, level) {
    const base = POKEMON_DATA[data.key];
    const hp = Math.floor((base.baseStats.hp * 2 * level) / 100) + level + 10;
    return {
      name: data.name,
      id: base.id,
      type1: base.type1,
      type2: base.type2,
      level: level,
      currentHP: hp,
      maxHP: hp,
      attack: Math.floor((base.baseStats.atk * 2 * level) / 100) + 5,
      defense: Math.floor((base.baseStats.def * 2 * level) / 100) + 5,
      spAtk: Math.floor((base.baseStats.spa * 2 * level) / 100) + 5,
      spDef: Math.floor((base.baseStats.spd * 2 * level) / 100) + 5,
      speed: Math.floor((base.baseStats.spe * 2 * level) / 100) + 5,
      moves: base.moves.map(m => ({ ...m })),
      statStages: { atk: 0, def: 0, spa: 0, spd: 0, spe: 0 }
    };
  }

  getCategory(move) {
    return SPECIAL_TYPES.includes(move.type) ? 'special' : 'physical';
  }

  calcDamage(attacker, defender, move) {
    const isPhysical = this.getCategory(move) === 'physical';
    let A = isPhysical ? attacker.attack : attacker.spAtk;
    let D = isPhysical ? defender.defense : defender.spDef;
    // Stat stage modifiers (simplified)
    const stageMod = (stage) => {
      if (stage >= 0) return (stage + 2) / 2;
      return 2 / (-stage + 2);
    };
    if (isPhysical) {
      A = Math.floor(A * stageMod(attacker.statStages.atk));
      D = Math.floor(D * stageMod(defender.statStages.def));
    } else {
      A = Math.floor(A * stageMod(attacker.statStages.spa));
      D = Math.floor(D * stageMod(defender.statStages.spd));
    }
    const L = attacker.level;
    const P = move.power;
    const damage = Math.floor((((2 * L / 5 + 2) * P * A / D) / 50) + 2);
    // STAB
    const stab = (attacker.type1 === move.type || attacker.type2 === move.type) ? 1.5 : 1;
    // Type effectiveness
    const type1Eff = this.getTypeEffectiveness(move.type, defender.type1);
    const type2Eff = defender.type2 ? this.getTypeEffectiveness(move.type, defender.type2) : 1;
    const typeEff = type1Eff * type2Eff;
    // Random factor (85-100)
    const random = (Math.random() * 16 + 85) / 100;
    return Math.floor(damage * stab * typeEff * random);
  }

  getTypeEffectiveness(moveType, targetType) {
    if (!targetType) return 1;
    const chart = TYPE_CHART[moveType];
    return chart && chart[targetType] !== undefined ? chart[targetType] : 1;
  }

  updateTransition(dt) {
    if (!this.transitionActive) return;
    this.transitionTimer += dt;
    switch (this.transitionPhase) {
      case 0: // Flash
        if (this.transitionTimer > 100) {
          this.transitionPhase = 1;
          this.transitionTimer = 0;
        }
        break;
      case 1: // Blackout
        if (this.transitionTimer > 200) {
          this.transitionPhase = 2;
          this.transitionTimer = 0;
        }
        break;
      case 2: // Mosaic reveal
        if (this.transitionTimer > 300) {
          this.transitionPhase = 3;
          this.transitionTimer = 0;
        }
        break;
      case 3: // Done
        this.transitionActive = false;
        this.inputLocked = false;
        break;
    }
  }

  drawTransition() {
    if (!this.transitionActive) return;
    const canvas = this.ctx.canvas;
    switch (this.transitionPhase) {
      case 0: // Flash white
        this.ctx.fillStyle = `rgba(255,255,255,${1 - this.transitionTimer / 100})`;
        this.ctx.fillRect(0, 0, canvas.width, canvas.height);
        break;
      case 1: // Blackout
        this.ctx.fillStyle = '#000';
        this.ctx.fillRect(0, 0, canvas.width, canvas.height);
        break;
      case 2: // Mosaic
        const step = Math.floor(this.transitionTimer / 50) + 1;
        this.ctx.fillStyle = '#000';
        this.ctx.fillRect(0, 0, canvas.width, canvas.height);
        this.ctx.fillStyle = '#87ceeb';
        for (let y = 0; y < canvas.height; y += step * 4) {
          for (let x = 0; x < canvas.width; x += step * 4) {
            if (Math.random() > 0.5) {
              this.ctx.fillRect(x, y, step * 4 - 1, step * 4 - 1);
            }
          }
        }
        break;
    }
  }

  drawBattleBackground() {
    // Sky gradient
    const gradient = this.ctx.createLinearGradient(0, 0, 0, 200);
    gradient.addColorStop(0, '#87ceeb');
    gradient.addColorStop(1, '#98d8aa');
    this.ctx.fillStyle = gradient;
    this.ctx.fillRect(0, 0, 480, 200);
    // Ground
    this.ctx.fillStyle = '#8b7355';
    this.ctx.fillRect(0, 200, 480, 120);
    this.ctx.fillStyle = '#9b8365';
    this.ctx.fillRect(0, 200, 480, 8);
  }

  drawBattlePlatforms() {
    // Enemy platform
    this.ctx.fillStyle = '#5a4a3a';
    this.ctx.beginPath();
    this.ctx.moveTo(280, 150);
    this.ctx.lineTo(400, 150);
    this.ctx.lineTo(380, 170);
    this.ctx.lineTo(300, 170);
    this.ctx.closePath();
    this.ctx.fill();
    this.ctx.strokeStyle = '#3a2a1a';
    this.ctx.lineWidth = 2;
    this.ctx.stroke();
    // Player platform
    this.ctx.fillStyle = '#5a4a3a';
    this.ctx.beginPath();
    this.ctx.moveTo(80, 230);
    this.ctx.lineTo(200, 230);
    this.ctx.lineTo(180, 250);
    this.ctx.lineTo(100, 250);
    this.ctx.closePath();
    this.ctx.fill();
    this.ctx.stroke();
  }

  drawEnemySprite() {
    const sprite = this.assets.get(`pokemon_${this.enemy.id}`);
    this.ctx.save();
    if (this.shakeTimer > 0 && this.phase === 'animate') {
      this.ctx.translate(Math.sin(this.shakeTimer * 0.5) * 5, 0);
    }
    if (sprite) {
      this.ctx.drawImage(sprite, 290, 70, 96, 96);
    } else {
      this.ctx.fillStyle = '#ff0000';
      this.ctx.fillRect(290, 70, 64, 64);
    }
    this.ctx.restore();
  }

  drawPlayerSprite() {
    const sprite = this.assets.get(`pokemon_back_${this.player.id}`);
    this.ctx.save();
    if (this.flashTimer > 0) {
      this.ctx.globalAlpha = Math.abs(Math.sin(this.flashTimer * 0.3));
    }
    if (sprite) {
      this.ctx.drawImage(sprite, 100, 150, 96, 96);
    } else {
      this.ctx.fillStyle = '#0000ff';
      this.ctx.fillRect(100, 150, 64, 64);
    }
    this.ctx.restore();
  }

  drawEnemyInfo() {
    const x = 20, y = 20;
    // Background frame (trapezoidal Gen 3 style)
    this.ctx.fillStyle = '#f8f8f8';
    this.ctx.beginPath();
    this.ctx.moveTo(x, y);
    this.ctx.lineTo(x + 180, y);
    this.ctx.lineTo(x + 200, y + 60);
    this.ctx.lineTo(x - 20, y + 60);
    this.ctx.closePath();
    this.ctx.fill();
    this.ctx.strokeStyle = '#5c4a3a';
    this.ctx.lineWidth = 3;
    this.ctx.stroke();
    // Pokemon name
    this.ctx.fillStyle = '#3a3a3a';
    this.ctx.font = 'bold 14px "Courier New"';
    this.ctx.fillText(this.enemy.name, x + 10, y + 18);
    // Level
    this.ctx.font = '12px "Courier New"';
    this.ctx.fillText(`Lv.${this.enemy.level}`, x + 150, y + 18);
    // HP bar background
    this.ctx.fillStyle = '#5c4a3a';
    this.ctx.fillRect(x + 5, y + 25, 160, 12);
    // HP bar
    const hpPercent = Math.max(0, this.enemyHP / this.enemyHPMax);
    const hpColor = hpPercent > 0.5 ? '#00ff00' : hpPercent > 0.2 ? '#ffff00' : '#ff0000';
    this.ctx.fillStyle = '#3a3a3a';
    this.ctx.fillRect(x + 6, y + 26, 158, 10);
    this.ctx.fillStyle = hpColor;
    const targetWidth = 158 * hpPercent;
    const currentWidth = this.enemyHP / this.enemyHPMax * 158;
    const animWidth = currentWidth + (targetWidth - currentWidth) * 0.1;
    this.ctx.fillRect(x + 6, y + 26, Math.max(0, animWidth), 10);
    // HP text
    this.ctx.fillStyle = '#fff';
    this.ctx.font = '10px "Courier New"';
    this.ctx.fillText(`${Math.floor(this.enemyHP)}/${this.enemyHPMax}`, x + 70, y + 35);
  }

  drawPlayerInfo() {
    const x = 260, y = 140;
    // Background frame
    this.ctx.fillStyle = '#f8f8f8';
    this.ctx.beginPath();
    this.ctx.moveTo(x, y);
    this.ctx.lineTo(x + 180, y);
    this.ctx.lineTo(x + 200, y + 80);
    this.ctx.lineTo(x - 20, y + 80);
    this.ctx.closePath();
    this.ctx.fill();
    this.ctx.strokeStyle = '#5c4a3a';
    this.ctx.lineWidth = 3;
    this.ctx.stroke();
    // Pokemon name
    this.ctx.fillStyle = '#3a3a3a';
    this.ctx.font = 'bold 14px "Courier New"';
    this.ctx.fillText(this.player.name, x + 30, y + 18);
    // Level
    this.ctx.font = '12px "Courier New"';
    this.ctx.fillText(`Lv.${this.player.level}`, x + 140, y + 18);
    // HP label
    this.ctx.fillText('HP', x + 10, y + 45);
    // HP bar background
    this.ctx.fillStyle = '#5c4a3a';
    this.ctx.fillRect(x + 35, y + 35, 160, 12);
    // HP bar
    const hpPercent = Math.max(0, this.playerHP / this.playerHPMax);
    const hpColor = hpPercent > 0.5 ? '#00ff00' : hpPercent > 0.2 ? '#ffff00' : '#ff0000';
    this.ctx.fillStyle = '#3a3a3a';
    this.ctx.fillRect(x + 36, y + 36, 158, 10);
    this.ctx.fillStyle = hpColor;
    const targetWidth = 158 * hpPercent;
    const currentWidth = this.playerHP / this.playerHPMax * 158;
    const animWidth = currentWidth + (targetWidth - currentWidth) * 0.1;
    this.ctx.fillRect(x + 36, y + 36, Math.max(0, animWidth), 10);
    // HP text
    this.ctx.fillStyle = '#fff';
    this.ctx.font = '10px "Courier New"';
    this.ctx.fillText(`${Math.floor(this.playerHP)}/${this.playerHPMax}`, x + 100, y + 45);
  }

  drawActionPanel() {
    const x = 20, y = 240;
    const w = 200, h = 70;
    // Background
    this.ctx.fillStyle = '#f8f8f8';
    this.ctx.fillRect(x, y, w, h);
    this.ctx.strokeStyle = '#5c4a3a';
    this.ctx.lineWidth = 3;
    this.ctx.strokeRect(x, y, w, h);
    // Action options
    const actions = ['FIGHT', 'BAG', 'RUN'];
    this.ctx.font = '14px "Courier New"';
    actions.forEach((action, i) => {
      const isSelected = this.actionSelection === i;
      this.ctx.fillStyle = isSelected ? '#5c4a3a' : '#3a3a3a';
      this.ctx.fillRect(x + 5 + i * 65, y + 10, 60, 25);
      this.ctx.fillStyle = isSelected ? '#fff' : '#3a3a3a';
      this.ctx.fillText(action, x + 15 + i * 65, y + 28);
    });
    // Move selection panel (when Fight is selected)
    if (this.phase === 'player_turn' && this.actionSelection === 0) {
      this.drawMoveSelection();
    }
  }

  drawMoveSelection() {
    const x = 240, y = 240;
    const w = 220, h = 70;
    this.ctx.fillStyle = '#f8f8f8';
    this.ctx.fillRect(x, y, w, h);
    this.ctx.strokeStyle = '#5c4a3a';
    this.ctx.lineWidth = 3;
    this.ctx.strokeRect(x, y, w, h);
    this.ctx.font = '12px "Courier New"';
    this.player.moves.forEach((move, i) => {
      const isSelected = this.selectedMove === i;
      this.ctx.fillStyle = isSelected ? '#5c4a3a' : '#3a3a3a';
      this.ctx.fillRect(x + 5 + (i % 2) * 105, y + 8 + Math.floor(i / 2) * 28, 100, 24);
      this.ctx.fillStyle = isSelected ? '#fff' : '#3a3a3a';
      this.ctx.fillText(move.name, x + 12 + (i % 2) * 105, y + 25 + Math.floor(i / 2) * 28);
      // Type indicator
      this.ctx.fillStyle = this.getTypeColor(move.type);
      this.ctx.fillRect(x + 85 + (i % 2) * 105, y + 12 + Math.floor(i / 2) * 28, 14, 14);
    });
  }

  getTypeColor(type) {
    const colors = {
      'Normal': '#a8a878', 'Fire': '#f08030', 'Water': '#6890f0', 'Grass': '#78c850',
      'Electric': '#f8d030', 'Ice': '#98d8d8', 'Fighting': '#c03028', 'Poison': '#a040a0',
      'Ground': '#e0c068', 'Flying': '#a890f0', 'Psychic': '#f85888', 'Bug': '#a8b820',
      'Rock': '#b8a038', 'Ghost': '#705898', 'Dragon': '#7038f8', 'Dark': '#705848',
      'Steel': '#b8b8d0'
    };
    return colors[type] || '#a8a878';
  }

  drawMessage() {
    if (!this.message) return;
    const boxX = 20, boxY = 175;
    const boxW = 440, boxH = 50;
    this.ctx.fillStyle = '#f8f8f8';
    this.ctx.fillRect(boxX, boxY, boxW, boxH);
    this.ctx.strokeStyle = '#5c4a3a';
    this.ctx.lineWidth = 3;
    this.ctx.strokeRect(boxX, boxY, boxW, boxH);
    this.ctx.fillStyle = '#3a3a3a';
    this.ctx.font = '14px "Courier New"';
    const displayText = this.message.substring(0, Math.floor(this.charIndex));
    const lines = displayText.split('\n');
    lines.forEach((line, i) => {
      this.ctx.fillText(line, boxX + 15, boxY + 25 + i * 18);
    });
    if (this.charIndex >= this.message.length) {
      this.ctx.fillText('▼', boxX + boxW - 25, boxY + boxH - 12);
    }
  }

  updateMessage(dt) {
    if (!this.message) return;
    if (this.charIndex < this.message.length) {
      this.charIndex += dt * 0.05;
      if (this.charIndex > this.message.length) {
        this.charIndex = this.message.length;
      }
    }
  }

  handleInput(key) {
    if (this.inputLocked) return;
    if (this.message && this.charIndex < this.message.length) {
      this.charIndex = this.message.length;
      return;
    }
    if (this.message && this.charIndex >= this.message.length) {
      this.message = '';
      if (this.messageQueue.length > 0) {
        this.message = this.messageQueue.shift();
        this.charIndex = 0;
      } else if (this.phase === 'result') {
        this.active = false;
        if (this.onBattleEnd) this.onBattleEnd(this.winner);
        return;
      }
      return;
    }
    if (this.phase === 'player_turn') {
      if (this.actionSelection === 0 && this.selectedMove !== null) {
        // Move selected, execute
        this.executePlayerMove();
      } else {
        this.handleActionInput(key);
      }
    }
  }

  handleActionInput(key) {
    if (key === 'ArrowUp' && this.actionSelection === 2) this.actionSelection = 0;
    else if (key === 'ArrowDown' && this.actionSelection === 0) this.actionSelection = 2;
    else if (key === 'ArrowLeft' && this.actionSelection === 2) this.actionSelection = 1;
    else if (key === 'ArrowRight' && this.actionSelection === 1) this.actionSelection = 2;
    else if (key === 'z' || key === 'Z') {
      if (this.actionSelection === 0) {
        // Enter move selection
        if (this.selectedMove !== null) {
          this.executePlayerMove();
        }
      } else if (this.actionSelection === 2) {
        // Run
        this.message = "Got away safely!";
        this.charIndex = 0;
        this.phase = 'result';
        this.winner = 'player';
      }
    }
    if (this.actionSelection === 0 && this.selectedMove === null) {
      // Move selection with arrow keys
      if (key === 'ArrowUp' || key === 'ArrowDown') {
        this.selectedMove = 0;
      } else if (key === 'ArrowLeft' || key === 'ArrowRight') {
        this.selectedMove = 0;
      }
    }
  }

  selectMove(index) {
    if (this.selectedMove === index) {
      this.executePlayerMove();
    } else {
      this.selectedMove = index;
    }
  }

  executePlayerMove() {
    if (this.selectedMove === null) return;
    const move = this.player.moves[this.selectedMove];
    this.inputLocked = true;
    this.phase = 'animate';
    this.performAttack(this.player, this.enemy, move, true);
  }

  executeEnemyMove() {
    const move = this.chooseEnemyMove();
    this.performAttack(this.enemy, this.player, move, false);
  }

  chooseEnemyMove() {
    // AI: prioritize super effective, then KO if possible, else random
    const moves = this.enemy.moves;
    let bestMove = moves[0];
    let bestScore = -Infinity;
    for (const move of moves) {
      let score = 0;
      const eff = this.getTypeEffectiveness(move.type, this.player.type1) *
                  (this.player.type2 ? this.getTypeEffectiveness(move.type, this.player.type2) : 1);
      score = eff;
      // Check if move can KO
      const dmg = this.calcDamage(this.enemy, this.player, move);
      if (dmg >= this.player.currentHP) score += 100;
      if (score > bestScore) {
        bestScore = score;
        bestMove = move;
      }
    }
    return bestMove;
  }

  performAttack(attacker, defender, move, isPlayer) {
    this.effectivenessText = '';
    const dmg = this.calcDamage(attacker, defender, move);
    const eff1 = this.getTypeEffectiveness(move.type, defender.type1);
    const eff2 = defender.type2 ? this.getTypeEffectiveness(move.type, defender.type2) : 1;
    const totalEff = eff1 * eff2;
    if (totalEff > 1) this.effectivenessText = "It's super effective!";
    else if (totalEff < 1) this.effectivenessText = "Not very effective...";
    // Critical hit check (simplified)
    const isCritical = Math.random() < 0.0625; // ~1/16 for Gen 3
    const finalDmg = isCritical ? Math.floor(dmg * 1.5) : dmg;
    if (isPlayer) {
      this.enemyHP = Math.max(0, this.enemyHP - finalDmg);
      this.shakeTimer = 20;
    } else {
      this.playerHP = Math.max(0, this.playerHP - finalDmg);
      this.flashTimer = 20;
    }
    let msg = `${attacker.name} used ${move.name}!`;
    if (isCritical) msg += '\nCritical hit!';
    if (this.effectivenessText) msg += `\n${this.effectivenessText}`;
    msg += `\n${finalDmg} damage!`;
    this.message = msg;
    this.charIndex = 0;
    this.phase = 'animate';
    setTimeout(() => {
      if ((isPlayer && this.enemyHP <= 0) || (!isPlayer && this.playerHP <= 0)) {
        this.phase = 'result';
        this.winner = isPlayer ? 'player' : 'enemy';
        this.message = `${defender.name} fainted!`;
        this.charIndex = 0;
        this.messageQueue = [];
        if (this.winner === 'player') {
          this.messageQueue.push(`You won!\n${this.player.name} gained experience!`);
        } else {
          this.messageQueue.push(`You lost!\n${this.player.name} fainted...`);
        }
        this.messageQueue.push('');
      } else {
        this.inputLocked = false;
        this.phase = isPlayer ? 'enemy_turn' : 'player_turn';
        this.selectedMove = null;
        this.actionSelection = 0;
        if (!isPlayer) {
          setTimeout(() => this.executeEnemyMove(), 1000);
        }
      }
      this.inputLocked = false;
    }, 1500);
  }

  update(dt) {
    if (!this.active) return;
    this.updateTransition(dt);
    this.updateMessage(dt);
    if (this.shakeTimer > 0) this.shakeTimer -= dt * 0.05;
    if (this.flashTimer > 0) this.flashTimer -= dt * 0.05;
  }

  draw() {
    if (!this.active) return;
    this.drawBattleBackground();
    this.drawTransition();
    this.drawBattlePlatforms();
    this.drawEnemySprite();
    this.drawPlayerSprite();
    this.drawEnemyInfo();
    this.drawPlayerInfo();
    this.drawActionPanel();
    this.drawMessage();
  }
}

// --- MAIN GAME ---
class Game {
  constructor() {
    this.canvas = document.getElementById('canvas');
    this.ctx = this.canvas.getContext('2d');
    this.assets = new AssetManager();
    this.mapEngine = null;
    this.battleEngine = null;
    this.state = 'loading'; // loading, map, battle
    this.keys = {};
    this.lastTime = 0;
    this.setupInput();
    this.loadAssets();
  }

  setupInput() {
    window.addEventListener('keydown', (e) => {
      this.keys[e.key] = true;
      this.handleKeyDown(e.key);
      if (['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight', ' '].includes(e.key)) {
        e.preventDefault();
      }
    });
    window.addEventListener('keyup', (e) => {
      this.keys[e.key] = false;
    });
  }

  handleKeyDown(key) {
    if (this.state === 'loading') {
      if (this.assets.loadedCount >= this.assets.loadingCount) {
        this.startGame();
      }
      return;
    }
    if (this.state === 'map') {
      if (key === 'z' || key === 'Z') {
        const result = this.mapEngine.interact();
        if (result === 'BATTLE') {
          this.startBattle();
        }
      }
    }
    if (this.state === 'battle') {
      this.battleEngine.handleInput(key);
    }
  }

  async loadAssets() {
    const progressFill = document.getElementById('progress-fill');
    this.assets.onProgress = (loaded, total) => {
      if (progressFill) progressFill.style.width = `${(loaded / total) * 100}%`;
    };
    this.assets.onComplete = () => {
      setTimeout(() => {
        document.getElementById('loading-screen').classList.add('hidden');
        this.state = 'map';
      }, 500);
    };
    // Sprite URLs from PokeAPI
    const sprites = {
      player: 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/back/25.png', // Pikachu as player proxy
      rival: 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/versions/generation-iii/emerald/261.png', // Poochyena
      // Enemy sprites
      pokemon_255: 'https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/255.png', // Torchic front
